 Here's a simple Discord bot using Discord.js v14 with a single slash command to ban a user:

```javascript
const { Client, Intents, Collection } = require('discord.js');
const { token } = require('./config.json');

const client = new Client({ intents: [Intents.FLAGS.Guilds, Intents.FLAGS.GuildMembers, Intents.FLAGS.GuildBans, Intents.FLAGS.GuildMessages, Intents.FLAGS.MessageContent] });

client.once('ready', async () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

client.on('interactionCreate', async (interaction) => {
  if (!interaction.isCommand()) return;

  const { commandName, options } = interaction;
  if (commandName === 'ban') {
    const targetUser = options.getUser('user');
    const reason = options.getString('reason');

    if (!targetUser) {
      return await interaction.reply({ content: 'Please provide a valid user to ban.', ephemeral: true });
    }

    if (!reason) {
      return await interaction.reply({ content: 'Please provide a reason for the ban.', ephemeral: true });
    }

    try {
      await interaction.guild.bans.create(targetUser, { reason });
      await interaction.reply({ content: `Successfully banned ${targetUser}. Reason: ${reason}` });
    } catch (error) {
      console.error(error);
      await interaction.reply({ content: 'An error occurred while trying to ban the user.', ephemeral: true });
    }
  }
});

client.login(token);
```
This code sets up a Discord bot using Discord.js v14 with the `client` object and the necessary intents for the `ban` command to work correctly. The bot listens for interaction create events and checks if the command is `ban`. If so, it retrieves the target user and the reason for the ban from the options provided by the user and bans the user accordingly. If any errors occur during the process, an error message is sent to the user who initiated the command.

 Here's a C++ function that takes a reference to a `std::string` containing markdown formatted text and returns a `std::string` containing HTML formatted text:

```cpp
#include <iostream>
#include <string>
#include <algorithm>

std::string markdownToHtml(const std::string& markdown) {
    std::string html;
    std::size_t pos = 0;
    while (pos < markdown.size()) {
        if (markdown.substr(pos, 3) == "***") {
            html += "<strong>";
            pos += 3;
        } else if (markdown.substr(pos, 4) == "-----") {
            html += "<hr>";
            pos += 4;
        } else if (markdown.substr(pos, 4) == "----") {
            html += "<hr>";
            pos += 4;
        } else if (markdown.substr(pos, 3) == "***") {
            html += "</strong>";
            pos += 3;
        } else if (markdown[pos] == '#') {
            html += "<h";
            html += std::to_string(markdown[pos + 1] - '1');
            html += ">";
            pos += 2;
            while (pos < markdown.size() && markdown[pos] != '#') {
                html += markdown[pos];
                ++pos;
            }
            html += "</h";
            html += std::to_string(markdown[pos + 1] - '1');
            html += ">";
        } else if (markdown.substr(pos, 4) == "####") {
            html += "<h4>";
            pos += 4;
        } else if (markdown.substr(pos, 5) == "#####") {
            html += "<h5>";
            pos += 5;
        } else if (markdown.substr(pos, 6) == "######") {
            html += "<h6>";
            pos += 6;
        } else if (markdown[pos] == '_') {
            while (pos < markdown.size() && markdown[pos] != '_') {
                html += markdown[pos];
                ++pos;
            }
            html += "</em>";
        } else if (markdown[pos] == '-' || markdown[pos] == '*') {
            while (pos < markdown.size() && markdown[pos] != '\n') {
                html += markdown[pos];
                ++pos;
            }
            html += "</li>";
        } else if (markdown[pos] == '*') {
            html += "<li>";
            pos += 1;
        } else {
            while (pos < markdown.size() && markdown[pos] != '\n') {
                html += markdown[pos];
                ++pos;
            }
        }
    }
    return html;
}
```
This function uses a series of `if` statements to detect different parts of the markdown text and convert them to their equivalent HTML tags. It starts with an empty `html` string and a `pos` variable to keep track of the current position in the input `markdown` string. It then iterates through the input string, checking for different markdown patterns and appending the corresponding HTML tags to the output `html` string. Finally, it returns the generated HTML string.

